Javascript.initialise:

		var partyAgainstNumber = WPU.getValue("/params/param[@name='xml']/WarrantReturn/PartyAgainstNumber");
		var def1Addr2 = WPU.getValue("/params/param[@name='xml']/ds/Warrant/Defendant1/Address/Line[2]");
		var def2Addr2 = WPU.getValue("/params/param[@name='xml']/ds/Warrant/Defendant2/Address/Line[2]");
		var partyAgainstAddr2 = "";
		if(partyAgainstNumber == 1) {
			partyAgainstAddr2 = def1Addr2;
		} else {
			partyAgainstAddr2 = def2Addr2; }
		var otherPossessAddr2 = WPU.getValue("/params/param[@name='xml']/ds/ManageCase/OtherPossessionAddress/Address/Line[2]");
		var possessAddr2 = "";
		if(otherPossessAddr2 != "") {
			possessAddr2 = otherPossessAddr2;
		} else {
			possessAddr2 = partyAgainstAddr2; }
		Services.setValue(PossessAdLine2.dataBinding, possessAddr2);
